mapper.select:
SELECT id, user_id, keyword, created_at, updated_at
FROM search_history
WHERE user_id = #{userId}
ORDER BY updated_at DESC
LIMIT #{limit}

mapper.delete:
DELETE FROM search_history
WHERE user_id = #{userId}
  AND id NOT IN (
      SELECT id FROM (
          SELECT id FROM search_history
          WHERE user_id = #{userId}
          ORDER BY updated_at DESC
          LIMIT #{keepCount}
      ) AS keep
  )

mapper.select:
SELECT keyword, COUNT(*) AS count
FROM search_history
WHERE updated_at >= #{startTime}
  AND updated_at <= #{endTime}
GROUP BY keyword
ORDER BY count DESC
LIMIT #{limit}

SELECT DATE(updated_at) AS date, COUNT(*) AS count
FROM search_history
WHERE updated_at >= #{startTime}
  AND updated_at <= #{endTime}
GROUP BY DATE(updated_at)
ORDER BY date

SELECT sh.id, sh.user_id, sh.keyword, sh.created_at, sh.updated_at, u.username FROM search_history sh LEFT JOIN users u ON u.id = sh.user_id
AND sh.user_id = #{userId} AND sh.keyword LIKE CONCAT('%', #{keyword}, '%')
ORDER BY sh.updated_at DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM search_history

    AND user_id = #{userId}
    AND keyword LIKE CONCAT('%', #{keyword}, '%')
